
// ---------- SEARCH FILTER ----------
const searchInput = document.getElementById("searchInput");
const comboItems = document.querySelectorAll(".combo-item");

if (searchInput && comboItems.length > 0) {

    const notFoundMsg = document.createElement("div");
    notFoundMsg.className = "text-center text-warning fw-bold mt-3 fs-5 col-md-10 mx-auto glass-card";
    notFoundMsg.innerText = " 😒 No matching model found !";
    notFoundMsg.style.display = "none";

    const container = document.querySelector(".combo-list-section .container");

    if (container) {
        container.appendChild(notFoundMsg);
    }

    searchInput.addEventListener("input", function () {

        const query = this.value.toLowerCase().trim();
        let foundAny = false;

        comboItems.forEach(item => {

            const mainEl = item.querySelector(".main-model");
            const compEl = item.querySelector(".compatible-model");

            if (!mainEl || !compEl) return;

            const mainText = mainEl.textContent;
            const compText = compEl.textContent;

            mainEl.innerHTML = mainText;
            compEl.innerHTML = compText;

            if (!query) {
                item.style.display = "block";
                notFoundMsg.style.display = "none";
                return;
            }

            if (compText.toLowerCase().includes(query)) {

                foundAny = true;
                item.style.display = "block";

                const regex = new RegExp(`(${query})`, "gi");

                compEl.innerHTML = compText.replace(
                    regex,
                    `<span class="highlight">$1</span>`
                );

            } else {

                item.style.display = "none";

            }

        });

        notFoundMsg.style.display = !foundAny && query !== "" ? "block" : "none";

    });
}